computed.formula:
/****************************************
 * Check at least one individual per row
 *
 * by Cinthia Romero
 ***************************************/
var entitiesGrid = this.PE_ENTITIES;
var entitiesGridRows = Object.keys(entitiesGrid).length;
var showMessageEntitiesIndividuals = {}; 
showMessageEntitiesIndividuals["SHOW"] = "YES";
showMessageEntitiesIndividuals["MESSAGE"] = "Please enter at least one entity";
if (entitiesGrid != undefined && entitiesGrid != null && entitiesGridRows > 0) {
    var entitiesIndividualsRowsOK = "YES";
    for (var i = 0; i < entitiesGridRows; i++) {
        var individualsGrid = entitiesGrid[i]["PE_INDIVIDUAL_INFORMATION"];
        var individualsGridRows = Object.keys(individualsGrid).length;
        if (individualsGrid == undefined || individualsGrid == null || individualsGridRows == 0 || individualsGrid[0]["PE_INDIVIDUAL_NAME"] == "" || individualsGrid[0]["PE_INDIVIDUAL_STATE_PROVINCE"] == "") {
            entitiesIndividualsRowsOK = "NO";
        }
    }
    if (entitiesIndividualsRowsOK == "YES") {
        showMessageEntitiesIndividuals["SHOW"] = "NO";
        showMessageEntitiesIndividuals["MESSAGE"] = "";
    } else {
        showMessageEntitiesIndividuals["MESSAGE"] = "All entities should have at least one individual. Consider that Individual Name and State/Province fields are required.";
    }
}
return showMessageEntitiesIndividuals;

/******************************
 * Validate Deal Team Comments
 * 
 * by Cinthia Romero
 *****************************/
var validateComments = "NO";
if (this.PE_SAVE_SUBMIT_LC6 != "SAVE" && this.PE_LAW_CLERK_COMMENTS != "" && this.PE_DEAL_TEAM_COMMENTS == "") {
    validateComments = "YES";
}
return validateComments;

/*********************
 * Set copy html link
 * 
 * by Cinthia Romero
 ********************/
 var dealFolder = this.PE_DEAL_FOLDER;
 var copyHTML = '<a onclick="navigator.clipboard.writeText(\'' + dealFolder + '\');" style="cursor:pointer"><br><img src="/public-files/copy.png" alt="Copy to Clipboard"> Copy </img></a>';
 return copyHTML;

custom_css:
[selector='margin'] {
    border: 2px solid var(--primary);
    padding: 12px;
}
[selector='color-text'] {
    color: var(--primary);
    font-weight: 800;
}
.lightBtn {
    color: #991a33;
    background-color: #FFFFFF;
    border: 1px solid #991a33 !important;
    border-radius: 4px;
    text-transform: capitalize;
    font-weight: 400;
    font-family: "arial";
  	font-size:14px;
    padding: 15px 7px 15px 7px ;
}
.lightBtn:hover {
  	background-color: #f9f9f9;
    color: #711426;
    text-decoration: none;
    cursor: pointer;
}
[selector='header']{
    margin-bottom: 20px;
}
[selector='title']{
    margin-bottom: 15px;
}
[selector='loop-inputs']{
    margin-bottom: 30px;
}
